transform_js:
var cats = rawData.rows.map(function(r) { return r.cat; });
var lows = rawData.rows.map(function(r) { return r.low; });
var highs = rawData.rows.map(function(r) { return r.high; });
transformedData = { cats: cats, lows: lows, highs: highs };

echarts_js:
option = {
  title: { text: 'Temperature Range (Monthly)', left: 'center' },
  tooltip: { trigger: 'axis' },
  xAxis: { type: 'category', data: transformedData.cats },
  yAxis: { type: 'value', name: 'Temp (C)' },
  series: [
    { name: 'Low', type: 'line', data: transformedData.lows, lineStyle: { opacity: 0 }, areaStyle: { opacity: 0 }, stack: 'range', symbol: 'none' },
    { name: 'Range', type: 'line', data: transformedData.highs.map(function(h, i) { return h - transformedData.lows[i]; }), lineStyle: { opacity: 0 }, areaStyle: { opacity: 0.5, color: '#5470c6' }, stack: 'range', symbol: 'none' }
  ]
};
